import React from "react";

function Preview({ data }) {
  return (
    <div style={{ width: "50%", paddingLeft: "20px" }}>
      <h2>Preview</h2>

      <h3>{data.name}</h3>
      <p>{data.email}</p>
      <p>{data.phone}</p>

      <h4>Skills</h4>
      <p>{data.skills}</p>
    </div>
  );
}

export default Preview;
